import anthropic
from dataclasses import dataclass
from typing import Union

client = anthropic.Anthropic()

@dataclass
class AnnotatedSegment:
    """A segment of the response with its supporting citations."""
    text: str
    citations: list  # List of source references

def parse_cited_response(response) -> list[AnnotatedSegment]:
    """
    Parse a Citations API response into annotated segments.
    Returns a list of (text, [citations]) pairs.
    """
    segments = []
    content = response.content
    i = 0

    while i < len(content):
        block = content[i]

        if block.type == 'text':
            text = block.text
            # Look ahead for a citations block
            citations = []
            if i + 1 < len(content) and content[i + 1].type == 'citations':
                citations = content[i + 1].citations
                i += 1  # Skip the citations block
            segments.append(AnnotatedSegment(text=text, citations=citations))

        i += 1

    return segments

def format_citation(citation) -> str:
    """Format a single citation for display."""
    if citation.type == 'page_location':
        start = citation.start_page_number
        end = citation.end_page_number
        if start == end:
            loc = f"p. {start}"
        else:
            loc = f"pp. {start}-{end}"
        return f"[{loc}] \"...{citation.cited_text[:80]}...\""
    elif citation.type == 'char_location':
        return f"[chars {citation.start_char_index}-{citation.end_char_index}] \"{citation.cited_text[:80]}\""
    return "[citation]"

def render_annotated_answer(segments: list[AnnotatedSegment]) -> str:
    """Render the full answer with inline citation references."""
    parts = []
    citation_registry = []

    for segment in segments:
        text = segment.text
        if segment.citations:
            citation_nums = []
            for c in segment.citations:
                citation_registry.append(format_citation(c))
                citation_nums.append(str(len(citation_registry)))
            text += f" [{','.join(citation_nums)}]"
        parts.append(text)

    result = ''.join(parts)
    if citation_registry:
        result += "\n\nSources:\n"
        for i, ref in enumerate(citation_registry, 1):
            result += f"  {i}. {ref}\n"
    return result

