import anthropic
import base64
from pathlib import Path

client = anthropic.Anthropic()

SUPPORTED_TYPES = {
    '.pdf': 'application/pdf',
    '.txt': 'text/plain',
}

class CitationError(Exception):
    pass

def load_document_for_citations(file_path: str) -> dict:
    """
    Load a file and return the appropriate API document block.
    Raises CitationError for unsupported file types.
    """
    path = Path(file_path)
    suffix = path.suffix.lower()

    if suffix not in SUPPORTED_TYPES:
        raise CitationError(
            f"Citations are only supported for PDF and plain text files. "
            f"Got: {suffix}. Convert {path.name} to PDF or .txt before submitting."
        )

    media_type = SUPPORTED_TYPES[suffix]

    with open(path, 'rb') as f:
        data = f.read()

    if suffix == '.txt':
        # Validate the file is valid UTF-8
        try:
            text_content = data.decode('utf-8')
        except UnicodeDecodeError:
            raise CitationError(f"{path.name} is not valid UTF-8 text.")

        return {
            "type": "document",
            "source": {"type": "text", "media_type": "text/plain", "data": text_content},
            "citations": {"enabled": True}
        }
    else:  # PDF
        if len(data) < 4 or data[:4] != b'%PDF':
            raise CitationError(f"{path.name} does not appear to be a valid PDF.")

        encoded = base64.standard_b64encode(data).decode('utf-8')
        return {
            "type": "document",
            "source": {"type": "base64", "media_type": "application/pdf", "data": encoded},
            "citations": {"enabled": True}
        }

def query_with_citations_safe(file_path: str, question: str) -> dict:
    """Query a document with citations, with full error handling."""
    try:
        doc_block = load_document_for_citations(file_path)
    except CitationError as e:
        return {"error": str(e), "citations": []}
    except FileNotFoundError:
        return {"error": f"File not found: {file_path}", "citations": []}

    try:
        response = client.beta.messages.create(
            model="claude-3-5-sonnet-20241022",
            max_tokens=1024,
            betas=["citations-2024-09-19"],  # Required — must not be omitted
            messages=[{
                "role": "user",
                "content": [doc_block, {"type": "text", "text": question}]
            }]
        )
    except anthropic.BadRequestError as e:
        return {"error": f"API rejected document: {e}", "citations": []}
    except anthropic.APIError as e:
        return {"error": f"API error: {e}", "citations": []}

    # Safely parse citations from response
    answer_parts = []
    all_citations = []

    for block in response.content:
        if getattr(block, 'type', None) == 'text':
            answer_parts.append(block.text)
        elif getattr(block, 'type', None) == 'citations':
            # Defensive: check citations attribute exists
            cits = getattr(block, 'citations', [])
            all_citations.extend(cits)

    return {
        "answer": ''.join(answer_parts),
        "citations": all_citations,
        "citation_count": len(all_citations),
        "has_citations": len(all_citations) > 0
    }

# Test with various file types
for fp in ['report.pdf', 'notes.txt', 'data.xlsx', 'missing.pdf']:
    result = query_with_citations_safe(fp, "Summarize the key findings.")
    if result.get('error'):
        print(f"ERROR ({fp}): {result['error']}")
    else:
        print(f"OK ({fp}): {result['citation_count']} citations found")
